import React, { useState, useCallback, memo } from "react";
import Header from "../components/Layout/Header";
import Sidebar from "../components/Layout/Sidebar";
import Footer from "../components/Layout/Footer";
import Table from "../components/Shared/Table";
import Button from "../components/Shared/Button";
import Input from "../components/Shared/Input";
import CardObra from "../components/Cards/CardObra";
import ModalActualizacion from "../components/Modal/ModalActualizacion";
import { useObras } from "../context/ObraContext";
import { getProgramas } from "../utils/api";
import { colorBarra, estadoLabel, formatearFechaHora } from "../utils/formatters";

const PROGRAMAS = getProgramas();
const ESTADOS   = [
  { value: "",            label: "Todos los estados" },
  { value: "actualizada", label: "Actualizada" },
  { value: "en_progreso", label: "En progreso" },
  { value: "pendiente",   label: "Pendiente" },
];

/* Barra de progreso en tabla */
const BarraPct = memo(function BarraPct({ pct }) {
  return (
    <div className="flex items-center gap-2 min-w-[100px]">
      <div className="flex-1 bg-gray-100 rounded-full h-1.5 overflow-hidden">
        <div className={`h-1.5 rounded-full ${colorBarra(pct)} transition-all duration-500`} style={{ width: `${pct}%` }} />
      </div>
      <span className="text-xs font-semibold text-gray-700 w-8 text-right">{pct}%</span>
    </div>
  );
});

/* Badge de estado */
const BadgeEstado = memo(function BadgeEstado({ estado }) {
  const info = estadoLabel(estado);
  return <span className={`badge ${info.clase} text-xs`}>{info.icono} {info.label}</span>;
});

export default function ListadoObras() {
  const {
    obrasFiltradas,
    obrasPaginadas,
    loading,
    busqueda, setBusqueda,
    filtroProg, setFiltroProg,
    filtroEst, setFiltroEst,
    pagina, setPagina,
    totalPaginas,
    orden, toggleOrden,
  } = useObras();

  const [obraModal, setObraModal] = useState(null);

  const abrirModal  = useCallback((obra) => setObraModal(obra), []);
  const cerrarModal = useCallback(() => setObraModal(null), []);

  /* Columnas tabla */
  const columnas = [
    {
      key:      "nombre",
      label:    "Nombre obra",
      onSort:   () => toggleOrden("nombre"),
      sortDir:  orden.campo === "nombre" ? orden.dir : undefined,
      render:   (o) => (
        <div>
          <p className="font-medium text-gray-800 text-sm leading-tight">{o.nombre}</p>
          <p className="text-xs text-gray-400 mt-0.5 lg:hidden">{o.programa}</p>
        </div>
      ),
    },
    {
      key:       "programa",
      label:     "Programa",
      onSort:    () => toggleOrden("programa"),
      sortDir:   orden.campo === "programa" ? orden.dir : undefined,
      className: "hidden lg:table-cell",
      cellClass: "hidden lg:table-cell",
      render:    (o) => (
        <span className="text-xs text-gray-600 bg-gray-100 px-2 py-1 rounded-full leading-tight max-w-[160px] block truncate">
          {o.programa}
        </span>
      ),
    },
    {
      key:      "porcentaje",
      label:    "% Avance",
      onSort:   () => toggleOrden("porcentaje"),
      sortDir:  orden.campo === "porcentaje" ? orden.dir : undefined,
      render:   (o) => <BarraPct pct={o.porcentaje} />,
    },
    {
      key:       "estado",
      label:     "Estado",
      onSort:    () => toggleOrden("estado"),
      sortDir:   orden.campo === "estado" ? orden.dir : undefined,
      render:    (o) => <BadgeEstado estado={o.estado} />,
    },
    {
      key:       "ultimaActualizacion",
      label:     "Última actualización",
      onSort:    () => toggleOrden("ultimaActualizacion"),
      sortDir:   orden.campo === "ultimaActualizacion" ? orden.dir : undefined,
      className: "hidden md:table-cell",
      cellClass: "hidden md:table-cell",
      render:    (o) => (
        <span className="text-xs text-gray-500 whitespace-nowrap">{formatearFechaHora(o.ultimaActualizacion)}</span>
      ),
    },
    {
      key:    "acciones",
      label:  "",
      render: (o) => (
        <Button
          size="sm"
          variant={o.estado === "actualizada" ? "secondary" : "primary"}
          onClick={(e) => { e.stopPropagation(); abrirModal(o); }}
          aria-label={`Actualizar ${o.nombre}`}
        >
          Actualizar
        </Button>
      ),
    },
  ];

  return (
    <div className="min-h-screen flex flex-col" style={{ backgroundColor: "#F5F3F0" }}>
      <Header />

      <div className="flex flex-1">
        <Sidebar />

        <main className="flex-1 px-4 sm:px-6 lg:px-8 py-6 max-w-7xl mx-auto w-full">

          {/* Título */}
          <div className="mb-6 animate-fade-in">
            <h1 className="text-2xl font-bold text-gray-800">Listado de obras</h1>
            <p className="text-gray-500 text-sm mt-1">
              {obrasFiltradas.length} obra{obrasFiltradas.length !== 1 ? "s" : ""} encontrada{obrasFiltradas.length !== 1 ? "s" : ""}
            </p>
          </div>

          {/* Filtros */}
          <div className="bg-white rounded-xl border border-gray-200 shadow-sm p-4 mb-4 animate-fade-in">
            <div className="flex flex-col sm:flex-row gap-3">
              {/* Búsqueda */}
              <div className="flex-1">
                <Input
                  id="busqueda-obras"
                  placeholder="Buscar por nombre..."
                  value={busqueda}
                  onChange={(e) => setBusqueda(e.target.value)}
                  aria-label="Buscar obras por nombre"
                />
              </div>

              {/* Filtro programa */}
              <select
                value={filtroProg}
                onChange={(e) => setFiltroProg(e.target.value)}
                className="px-3 py-2 text-sm rounded-lg border border-gray-300 bg-white text-gray-700
                  focus:outline-none focus:ring-2 focus:ring-primary-500 focus:border-primary-500
                  hover:border-gray-400 transition-colors"
                aria-label="Filtrar por programa"
              >
                <option value="">Todos los programas</option>
                {PROGRAMAS.map((p) => (
                  <option key={p} value={p}>{p}</option>
                ))}
              </select>

              {/* Filtro estado */}
              <select
                value={filtroEst}
                onChange={(e) => setFiltroEst(e.target.value)}
                className="px-3 py-2 text-sm rounded-lg border border-gray-300 bg-white text-gray-700
                  focus:outline-none focus:ring-2 focus:ring-primary-500 focus:border-primary-500
                  hover:border-gray-400 transition-colors"
                aria-label="Filtrar por estado"
              >
                {ESTADOS.map((e) => (
                  <option key={e.value} value={e.value}>{e.label}</option>
                ))}
              </select>

              {/* Limpiar filtros */}
              {(busqueda || filtroProg || filtroEst) && (
                <Button
                  variant="ghost"
                  size="md"
                  onClick={() => { setBusqueda(""); setFiltroProg(""); setFiltroEst(""); }}
                  aria-label="Limpiar todos los filtros"
                >
                  ✕ Limpiar
                </Button>
              )}
            </div>
          </div>

          {/* Contenido: tabla en desktop, acordeón en móvil */}
          {loading ? (
            <div className="flex items-center justify-center py-16">
              <div className="w-8 h-8 border-4 border-primary-500 border-t-transparent rounded-full animate-spin" />
            </div>
          ) : (
            <>
              {/* Vista desktop: tabla */}
              <div className="hidden sm:block animate-fade-in">
                <Table
                  columns={columnas}
                  data={obrasPaginadas}
                  emptyMessage="No se encontraron obras con los filtros seleccionados."
                />
              </div>

              {/* Vista móvil: acordeón */}
              <div className="sm:hidden space-y-3 animate-fade-in">
                {obrasPaginadas.length === 0 ? (
                  <div className="text-center py-10 text-gray-400 text-sm bg-white rounded-xl border border-gray-200">
                    No se encontraron obras con los filtros seleccionados.
                  </div>
                ) : (
                  obrasPaginadas.map((obra) => (
                    <CardObra key={obra.id} obra={obra} onActualizar={abrirModal} />
                  ))
                )}
              </div>

              {/* Paginación */}
              {totalPaginas > 1 && (
                <div className="flex items-center justify-between mt-4 px-1 animate-fade-in">
                  <p className="text-xs text-gray-500">
                    Página {pagina} de {totalPaginas} · {obrasFiltradas.length} obras
                  </p>
                  <div className="flex gap-1">
                    <Button
                      variant="secondary"
                      size="sm"
                      disabled={pagina === 1}
                      onClick={() => setPagina((p) => p - 1)}
                      aria-label="Página anterior"
                    >
                      ← Anterior
                    </Button>
                    {Array.from({ length: totalPaginas }, (_, i) => i + 1)
                      .filter((p) => p === 1 || p === totalPaginas || Math.abs(p - pagina) <= 1)
                      .reduce((acc, p, i, arr) => {
                        if (i > 0 && p - arr[i - 1] > 1) acc.push("...");
                        acc.push(p);
                        return acc;
                      }, [])
                      .map((item, i) =>
                        item === "..." ? (
                          <span key={`sep-${i}`} className="px-2 py-1 text-gray-400 text-sm self-center">…</span>
                        ) : (
                          <Button
                            key={item}
                            size="sm"
                            variant={item === pagina ? "primary" : "secondary"}
                            onClick={() => setPagina(item)}
                            aria-label={`Ir a página ${item}`}
                            aria-current={item === pagina ? "page" : undefined}
                          >
                            {item}
                          </Button>
                        )
                      )}
                    <Button
                      variant="secondary"
                      size="sm"
                      disabled={pagina === totalPaginas}
                      onClick={() => setPagina((p) => p + 1)}
                      aria-label="Página siguiente"
                    >
                      Siguiente →
                    </Button>
                  </div>
                </div>
              )}
            </>
          )}
        </main>
      </div>

      <Footer />

      {/* Modal */}
      {obraModal && (
        <ModalActualizacion obra={obraModal} onClose={cerrarModal} />
      )}
    </div>
  );
}
